func ganttStyle(g SpanGeom) templ.SafeCSS {
	return templ.SafeCSS(fmt.Sprintf("left:%.2f%%;width:%.2f%%", g.Offset, g.Width))
}

func pluralS(n int) string {
	if n == 1 {
		return ""
	}
	return "s"
}

// rollupCostLbl appends " · total" to the cost metric label when a run's cost
// includes sub-agents, so it's clear the headline number is the rolled-up
// figure and not just the parent's own spend.
func rollupCostLbl(c CostRollup) string {
	if c.HasSubs() {
		return " · total"
	}
	return ""
}

// turnModelShort is the compact model label shown on the turn summary line —
// the model name when known, falling back to the provider. Empty for legacy
// traces with no provenance.
func turnModelShort(t TurnNode) string {
	if t.Model != "" {
		return t.Model
	}
	return t.Provider
}

// turnProviderTitle composes a hover tooltip for the provider badge shown
// next to llm_call. Surfaces the same info the per-step trace already
// stores but in a format readable at a glance — "openai · gpt-x · ****a2Fn ·
// fallback" when applicable. Empty when the turn has no provenance
// (legacy trace).
func turnProviderTitle(t TurnNode) string {
	if t.Provider == "" {
		return ""
	}
	out := t.Provider
	if t.Model != "" {
		out += " · " + t.Model
	}
	if t.APIKeySuffix != "" {
		out += " · " + t.APIKeySuffix
	}
	if t.Fallback {
		out += " · fallback"
	}
	return out
}

